546	
547	    /// Helper to create a minimal `SandboxPolicy` with the given process policy.
548	    fn policy_with_process(process: ProcessPolicy) -> SandboxPolicy {
549	        SandboxPolicy {
550	            version: 1,
551	            filesystem: FilesystemPolicy::default(),
552	            network: NetworkPolicy::default(),
553	            landlock: LandlockPolicy::default(),
554	            process,
