558	    #[test]
559	    fn drop_privileges_noop_when_no_user_or_group() {
560	        let policy = policy_with_process(ProcessPolicy {
561	            run_as_user: None,
562	            run_as_group: None,
563	        });
564	        if nix::unistd::geteuid().is_root() {
565	            // As root, drop_privileges falls back to "sandbox:sandbox".
566	            // If that user exists, it succeeds; if not (e.g. CI), it
567	            // must error rather than silently keep root.
568	            let has_sandbox = User::from_name("sandbox").ok().flatten().is_some();
569	            assert_eq!(drop_privileges(&policy).is_ok(), has_sandbox);
570	        } else {
571	            assert!(drop_privileges(&policy).is_ok());
572	        }
573	    }
