589	    #[test]
590	    fn drop_privileges_succeeds_for_current_user() {
591	        // Resolve the current user's name so we can ask drop_privileges to
592	        // "switch" to the user we're already running as.  This exercises the
593	        // full verification path (getegid/geteuid checks) without needing root.
594	        let current_user = User::from_uid(nix::unistd::geteuid())
595	            .expect("getpwuid")
596	            .expect("current user entry");
597	        let current_group = Group::from_gid(nix::unistd::getegid())
598	            .expect("getgrgid")
599	            .expect("current group entry");
600	
601	        let policy = policy_with_process(ProcessPolicy {
602	            run_as_user: Some(current_user.name),
603	            run_as_group: Some(current_group.name),
604	        });
605	
606	        assert!(drop_privileges(&policy).is_ok());
607	    }
